import{_ as e,o as s,c as o,an as a}from"./chunks/framework.D5fFzH9V.js";const i="/images/contacts.png",r="/images/display_presence_information.png",n="/images/block_external_domains.png",c="/images/skype_users_off.png",y=JSON.parse('{"title":"Microsoft Teams Status Disclosure","description":"This is a standard description","frontmatter":{"pageClass":"blog-page","title":"Microsoft Teams Status Disclosure","author":"Christoph Mahrl","description":"This is a standard description","tags":"hardening,privacy,teams","date":"2022-08-02T00:00:00.000Z","cover":"/images/teams-status-disclosure-cover-16x9.png"},"headers":[],"relativePath":"blog/microsoft-teams-status-disclosure.md","filePath":"blog/microsoft-teams-status-disclosure.md"}'),u={name:"blog/microsoft-teams-status-disclosure.md"};function l(p,t,h,m,d,g){return s(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="microsoft-teams-status-disclosure" tabindex="-1">Microsoft Teams Status Disclosure <a class="header-anchor" href="#microsoft-teams-status-disclosure" aria-label="Permalink to &quot;Microsoft Teams Status Disclosure&quot;">​</a></h1><p>The &quot;status light&quot; in MS Teams is pretty inconspicuous, but it reveals quite a lot about you and your habits: when you start work and when you stop, whether you’re currently on a coffee break with colleagues, sitting through a meeting, or even presenting right at this moment.</p><p>Status information may be quite useful within an organization, but by default, people outside your organization may also be able to see your presence status. We’ve noticed that this is the case for many of our contacts.</p><p><img src="'+i+'" alt="Contact list with status" width="50%"></p><h2 id="remediation" tabindex="-1">Remediation <a class="header-anchor" href="#remediation" aria-label="Permalink to &quot;Remediation&quot;">​</a></h2><p>If you don’t want that, the default configuration must be adjusted in the Teams Admin Center. But first: unfortunately, there is no way to completely disable access to status information for external users.</p><p>However, you do have the following options to prevent access; although with limitations:</p><p>Option 1) Enable Skype for Business Presence Privacy Mode. This option restricts access to presence information to Skype for Business or Teams contacts on your personal contact list.</p><p><img src="'+r+'" alt="Display presence information only for a user&#39;s contacts"></p><p>Option 2) Block all external domains. This means your colleagues can’t search for, call, chat with, or schedule meetings with anyone outside your organization. Exchanging with others is then only possible via guest access.</p><p><img src="'+n+'" alt="Block all external domains"></p><p>While you’re hardening MS Teams, you should also disable the option that allows people to communicate with Skype users.</p><p><img src="'+c+'" alt="Don&#39;t allow communication with Skype users"></p><h2 id="other-suggestions" tabindex="-1">Other suggestions? <a class="header-anchor" href="#other-suggestions" aria-label="Permalink to &quot;Other suggestions?&quot;">​</a></h2><p>Is there a better way? Do you have feedback?</p><p><a href="/contact-us">Write us!</a></p>',16)])])}const _=e(u,[["render",l]]);export{y as __pageData,_ as default};
